INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-64311456-moex-00665', 'elementary-64311456', 'elementary-64311456-moex-111-01c5eaab', 'sub-elementary-64311456-05', NULL, 'single_choice', '承上題，本文意旨為：', '["凡事應心存感恩", "人不可錙銖必較", "禮貌使社會溫暖", "金錢絕不是萬能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00666', 'elementary-64311456', 'elementary-64311456-moex-111-01c5eaab', 'sub-elementary-64311456-05', NULL, 'single_choice', '「理想的下午，當消使在理想的地方，通常這地方是在城市。幽靜田村，風景美極，空氣水質好極， 卻是清晨夜晚都好，下午難免苦長。理想的下午，有賴理想的下午人。這類人樂意享受外間。樂意 暫且擱下手邊工作，樂意走出舒適的廳房、關掉柔美的音樂、闔上津津有味的書籍，套上鞋往外而 去。也只是漫無目的的走，看看市景，聽聽人聲。穿過馬路，登上台階，時而進入公園，看一眼花 草，瞧一眼池魚。揀一方大石或鐵椅坐下，不時側聽鄰客高談時政，嗅著飄來的香菸味，置之一笑。 有時翻閱小報，悄然睏去。醒來只覺眼前景物的色調略呈灰藍，像套了濾色鏡，不似先前那麼光燦 了，竟如同眾人散場多時只遺自己一個的那股辰光向晚寂寂。然一看錶，只過了十五分鐘。」 根據上文，下列何者最符合作者所謂「理想的下午」？', '["請假半天，在幽靜的山間園林尋幽訪勝", "暫時放下工作，帶一本小書到公園長椅上閒坐閱讀", "坐在城市的小咖啡廳，欣賞音樂與窗外風景，嗅著鄰座飄來的菸味", "帶著一顆悠閒的心，在城市中漫步閒坐，隨意地體驗城市中的百態"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00667', 'elementary-64311456', 'elementary-64311456-moex-111-01c5eaab', 'sub-elementary-64311456-05', NULL, 'single_choice', '承上題，作者認為「理想的下午」應該發生在城市中，依引文推測，最可能的原因是什麼？', '["身處在熱鬧塵俗之中，正可以靜觀世間多種趣味", "偷得浮生半日閒，時間所限，難以探訪鄉間美景", "交通方便，商業活動頻繁，可以調劑無聊的午後", "城市中人來人往，個人做什麼都不至於感到孤寂"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00668', 'elementary-64311456', 'elementary-64311456-moex-111-01c5eaab', 'sub-elementary-64311456-05', NULL, 'single_choice', '「財團法人國家文化藝術基金會」為辦理「國家文藝獎」，請全國文教機構與相關單位，推薦適當 人選，其使用之公文為：', '["簽", "呈", "咨", "函"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00669', 'elementary-64311456', 'elementary-64311456-moex-111-01c5eaab', 'sub-elementary-64311456-05', NULL, 'single_choice', '下列公文中稱謂用語，何者正確？', '["對於上級機關，為表尊敬，應以「貴」稱之", "對於機關首長，為表尊敬，應以「臺端」稱之", "無論與其他機構有無隸屬關係，皆可用「本」自稱", "為尊重性別平權，不宜使用「先生」、「女士」，應一律稱「君」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00670', 'elementary-64311456', 'elementary-64311456-moex-111-01c5eaab', 'sub-elementary-64311456-05', NULL, 'single_choice', '下列有關公文傳真的敘述，何者是錯誤的？', '["公文傳真應以原件為之，不宜用影印本傳真", "各機關因處理傳真公文需要之章戳，得自行刻用之", "完成陳核、繕校，未蓋用印信或簽署前，為爭取時效，得先行傳真", "傳真發文時，應先登錄傳真公文登記表（簿），記載相關事項、加蓋傳真作業人員名章及確認受 方電話、身分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00671', 'elementary-64311456', 'elementary-64311456-moex-111-01c5eaab', 'sub-elementary-64311456-05', NULL, 'single_choice', '下列選項用語使用正確的是：', '["謝謝您惠賜大作，敝刊倍增光彩", "小犬身體不適，我代他向您請假", "國家政通人和，百姓應居安思危", "在下仁民愛物，是難能可貴之才 杯水車薪的物價，令人喘不過氣"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00672', 'elementary-64311456', 'elementary-64311456-moex-111-01c5eaab', 'sub-elementary-64311456-05', NULL, 'single_choice', '下列各選項「 」內的詞語，使用正確的是：', '["近日的芬普尼毒蛋事件，使食安問題再度「引人遐思」", "世大運慶功遊行，所到之處「萬人空巷」，高舉旗幟夾道歡迎", "強颱直撲的新聞發布後，民眾不敢「掉以輕心」，均謹慎防颱", "企業投下鉅資邀請知名影星為產品代言，希望能讓銷售量「推陳出新」 舉重選手於世大運奪得金牌並破世界紀錄的一刻，全場觀眾「破涕為笑」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00673', 'elementary-64311456', 'elementary-64311456-moex-111-01c5eaab', 'sub-elementary-64311456-05', NULL, 'single_choice', '「柏克萊使我睜開眼睛，更迫切地觀察社會體認社會；在觀察和體認之餘，我並沒有感覺知識無能， 我反而更信仰知識的力量。知識是力量，但知識不可以禁閉在學院裡，知識必須釋放，放到現實社 會裡，方才是力量。學院要提供博大開放的文理科教育，所謂liberal arts 的教育，這種教育雖然可 能賦予學生日後謀生的技能，但那並不是最重要的目的；這種教育要使學生在潛默中體會到知識份 子的責任，介入社會而不為社會所埋葬──而我相信這是絕對可能的。我樂觀，因為樂觀乃是柏克萊 精神的真諦。」 根據上文，下列選項敘述正確的是：', '["柏克萊精神，是充滿樂觀與現實關懷", "知識是力量，但必須釋放到現實社會", "文理科教育主要目的是訓練謀生技能", "知識份子的責任是介入社會並保持獨立自主的判斷 學院教育與社會關懷雖有衝突，但仍必須積極調合"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
  ('elementary-64311456-moex-00674', 'elementary-64311456', 'elementary-64311456-moex-111-01c5eaab', 'sub-elementary-64311456-05', NULL, 'single_choice', '「時間是善良的，還是邪惡的魔術師呢？不是，時間只是一種簡單的乘法，另把原來的數值倍增而 已。開始變壞的米飯，每一天都不斷變得更腐臭。而開始變醇的美酒，每一分鐘，都在繼續增加它 的芬芳。在人世間，我們也曾經看過天真的少年一旦開始墮落，便不免愈陷愈深，終於變得滿臉風 塵，面目可憎。但是相反的，時間卻把溫和的笑痕，體諒的眼神，成熟的風采，智慧的神韻添加在 那些追尋善良的人身上。同樣是煮熟的米，壞飯與美酒的差別在哪裡呢？就在那一點點酒麴。同樣 是父母所生，誰墮落如禽獸，而誰又能提升成完美的人呢？是內心深處，緊緊環抱不放的，求真求 善的渴望。」 依據上文，符合文意的是：', '["時間非善非惡，只會增加原本數值", "掌握利用時間，是處世智慧的關鍵", "自我如何期許，時間也會如何對待", "透過時間積累，自能達到偉大成就 時間力量強大，人類永遠無法對抗"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "502", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL)
